import math

def get_min_exchanges(a, x, y):
    def find_min_steps(target):
        steps = 0
        while target != 0:
            if target & 1:
                steps += 1
            target >>= 1
        return steps

    steps_x = find_min_steps(a[x-1])
    steps_y = find_min_steps(a[y-1])
    return max(steps_x, steps_y)

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    max_m = -1
    best_pair = (0, 0)

    for i in range(n):
        for j in range(i+1, n):
            m = get_min_exchanges(a, i, j)
            if m > max_m:
                max_m = m
                best_pair = (i+1, j+1)

    x, y = best_pair
    print(f"{x} {y} {max_m}")

if __name__ == "__main__":
    main()"}

