def kosaraju(adj, n):
    visited = [False] * n
    order = []
    for u in range(n):
        if not visited[u]:
            stack = [(u, False)]
            while stack:
                node, processed = stack.pop()
                if processed:
                    order.append(node)
                    continue
                if visited[node]:
                    continue
                visited[node] = True
                stack.append( (node, True) )
                for v in adj[node]:
                    if not visited[v]:
                        stack.append( (v, False) )
    # Reverse the graph
    adj_rev = [[] for _ in range(n)]
    for u in range(n):
        for v in adj[u]:
            adj_rev[v].append(u)
    # Second pass
    visited = [False] * n
    count = 0
    for u in reversed(order):
        if not visited[u]:
            stack = [u]
            visited[u] = True
            while stack:
                node = stack.pop()
                for v in adj_rev[node]:
                    if not visited[v]:
                        visited[v] = True
                        stack.append(v)
